import java.util.Scanner;

public class SecureBufferHandling {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Allocate a fixed-size buffer
        int bufferSize = 10;
        byte[] buffer = new byte[bufferSize];

        // Truncate or limit the user input to fit within the buffer size
        byte[] userInputBytes = userInput.getBytes();
        int lengthToCopy = Math.min(userInputBytes.length, bufferSize);

        // Copy the limited bytes into the buffer
        System.arraycopy(userInputBytes, 0, buffer, 0, lengthToCopy);

        System.out.println("User input length: " + lengthToCopy);
    }
}

### Explanation:
취약유형: Buffer Overflow
